function getNodeJson(name) {
  try {
    return $(name).first().json || {};
  } catch (e) {
    try {
      const arr = $items(name);
      return arr && arr[0] ? arr[0].json : {};
    } catch (e2) {
      return {};
    }
  }
}

function removeAccents(text) {
  return String(text || "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "");
}

function normalizeBase(text) {
  return removeAccents(text)
    .toUpperCase()
    .replace(/@\w+/g, " ")
    .replace(/[.,;:()_\-\/\\]/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizeClientName(text) {
  return normalizeBase(text)
    .replace(/\b(SPA|S A|SA|LTDA|LIMITADA|EIRL|E I R L|CHILE|COMERCIAL|COMERCIALIZADORA|DISTRIBUIDORA|IMPORTADORA)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function normalizePhonetic(text) {
  return normalizeClientName(text)
    .replace(/Y/g, "I")
    .replace(/TH/g, "T")
    .replace(/PH/g, "F")
    .replace(/CK/g, "K")
    .replace(/QU/g, "K")
    .replace(/C(?=[EI])/g, "S")
    .replace(/C/g, "K")
    .replace(/Z/g, "S")
    .replace(/V/g, "B")
    .replace(/\s+/g, " ")
    .trim();
}

function extractClientQuery(message) {
  return normalizeBase(message)
    .replace(/\b(CUAL|CUÁL|ES|EL|LA|LOS|LAS|DE|DEL|SU|SUS|MI|MIS|MONTO|DEUDA|SALDO|PENDIENTE|CARTERA|CLIENTE|CUANTO|CUÁNTO|DEBE|TIENE|MUESTRA|DAME|POR|FAVOR)\b/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function levenshtein(a, b) {
  a = String(a || "");
  b = String(b || "");
  const matrix = Array.from({ length: a.length + 1 }, () => []);

  for (let i = 0; i <= a.length; i++) matrix[i][0] = i;
  for (let j = 0; j <= b.length; j++) matrix[0][j] = j;

  for (let i = 1; i <= a.length; i++) {
    for (let j = 1; j <= b.length; j++) {
      const cost = a[i - 1] === b[j - 1] ? 0 : 1;
      matrix[i][j] = Math.min(
        matrix[i - 1][j] + 1,
        matrix[i][j - 1] + 1,
        matrix[i - 1][j - 1] + cost
      );
    }
  }

  return matrix[a.length][b.length];
}

function similarity(a, b) {
  if (!a || !b) return 0;
  const maxLen = Math.max(a.length, b.length);
  if (maxLen === 0) return 0;
  return 1 - levenshtein(a, b) / maxLen;
}

function scoreClient(query, clientName) {
  const q = normalizeClientName(query);
  const c = normalizeClientName(clientName);

  const qPh = normalizePhonetic(query);
  const cPh = normalizePhonetic(clientName);

  if (!q || !c) return 0;

  if (q === c) return 1;
  if (c.includes(q) && q.length >= 3) return 0.96;
  if (q.includes(c) && c.length >= 3) return 0.94;

  if (qPh === cPh) return 0.98;
  if (cPh.includes(qPh) && qPh.length >= 3) return 0.95;
  if (qPh.includes(cPh) && cPh.length >= 3) return 0.93;

  const qTokens = q.split(" ").filter(t => t.length >= 3);
  const cTokens = c.split(" ").filter(t => t.length >= 3);

  let bestTokenScore = 0;
  for (const qt of qTokens) {
    for (const ct of cTokens) {
      bestTokenScore = Math.max(bestTokenScore, similarity(qt, ct));
    }
  }

  let overlap = 0;
  for (const qt of qTokens) {
    if (cTokens.some(ct => ct.includes(qt) || qt.includes(ct))) overlap++;
  }

  const overlapScore = qTokens.length ? overlap / qTokens.length : 0;
  const fullScore = Math.max(similarity(q, c), similarity(qPh, cPh));

  return Math.max(bestTokenScore * 0.85, overlapScore * 0.9, fullScore * 0.8);
}

const datosSP = getNodeJson("Obtener Datos SP");
const limpiar = getNodeJson("Limpiar mensaje");
const telegram = getNodeJson("Telegram Trigger");

const inputActual = $input.first().json || {};

const mensajeOriginal =
  limpiar.mensaje_limpio ||
  limpiar.mensaje ||
  limpiar.text ||
  limpiar.chatInput ||
  inputActual.mensaje ||
  inputActual.text ||
  telegram.message?.text ||
  "";

const listaClientes = datosSP.clientes_cartera?.lista || [];
const queryCliente = extractClientQuery(mensajeOriginal);

let resultados = [];

if (queryCliente && listaClientes.length) {
  resultados = listaClientes
    .map(c => ({
      cliente: c.cliente,
      rut: c.rut,
      score: scoreClient(queryCliente, c.cliente),
      data: c,
    }))
    .filter(r => r.score >= 0.55)
    .sort((a, b) => b.score - a.score);
}

const top = resultados[0];
const segundo = resultados[1];

let estado_match = "sin_coincidencia";
let cliente_resuelto = null;
let candidatos = resultados.slice(0, 3).map(r => ({
  cliente: r.cliente,
  score: Number(r.score.toFixed(3)),
}));

let mensaje_agente = mensajeOriginal;

if (top && top.score >= 0.78 && (!segundo || (top.score - segundo.score) >= 0.08)) {
  estado_match = "coincidencia_alta";
  cliente_resuelto = top.cliente;

  mensaje_agente =
`Consulta del usuario: ${mensajeOriginal}

Cliente resuelto: ${top.cliente}
RUT: ${top.rut || "no disponible"}

Usa Cliente resuelto para responder. Si el texto escrito por el usuario no coincide exactamente, interpreta que se refiere a Cliente resuelto.`;
} else if (top && top.score >= 0.65) {
  estado_match = "coincidencia_ambigua";

  mensaje_agente =
`Consulta del usuario: ${mensajeOriginal}

Coincidencia de cliente ambigua. Posibles clientes:
${candidatos.map((c, i) => `${i + 1}. ${c.cliente}`).join("\n")}

Pide al usuario precisar a cuál cliente se refiere. No entregues montos hasta confirmar el cliente correcto.`;
}

return [
  {
    json: {
      ...inputActual,
      mensaje_original: mensajeOriginal,
      cliente_query: queryCliente,
      estado_match,
      cliente_resuelto,
      candidatos_cliente: candidatos,
      mensaje_agente,
    },
  },
];
